import{_ as e,o as a,c as s,Q as o}from"./chunks/framework.0e8ae64e.js";const f=JSON.parse('{"title":"Upgrading From Version 0.14.x to 0.15.0","description":"","frontmatter":{},"headers":[],"relativePath":"guide/upgrading-from-v0-14-to-v0-15.md","filePath":"guide/upgrading-from-v0-14-to-v0-15.md","lastUpdated":1730208540000}'),n={name:"guide/upgrading-from-v0-14-to-v0-15.md"},t=o('<h1 id="upgrading-from-version-0-14-x-to-0-15-0" tabindex="-1">Upgrading From Version 0.14.x to 0.15.0 <a class="header-anchor" href="#upgrading-from-version-0-14-x-to-0-15-0" aria-label="Permalink to &quot;Upgrading From Version 0.14.x to 0.15.0&quot;">​</a></h1><p>asdf versions 0.14.1 and older were written in Bash and distributed as a set of Bash scripts with the <code>asdf</code> function loaded into your shell. asdf version 0.15.0 is a complete rewrite of asdf in Go. Since it is a complete rewrite there are a number of breaking changes and it is now distributed as a binary rather than a set of scripts.</p><h2 id="breaking-changes" tabindex="-1">Breaking Changes <a class="header-anchor" href="#breaking-changes" aria-label="Permalink to &quot;Breaking Changes&quot;">​</a></h2><h3 id="hyphenated-commands-have-been-removed" tabindex="-1">Hyphenated commands have been removed <a class="header-anchor" href="#hyphenated-commands-have-been-removed" aria-label="Permalink to &quot;Hyphenated commands have been removed&quot;">​</a></h3><p>asdf version 0.14.1 and earlier supported by hyphenated and non-hyphenated versions of certain commands. With version 0.15.0 only the non-hyphenated versions are supported. The affected commands:</p><ul><li><code>asdf list-all</code> -&gt; <code>asdf list all</code></li><li><code>asdf plugin-add</code> -&gt; <code>asdf plugin add</code></li><li><code>asdf plugin-list</code> -&gt; <code>asdf plugin list</code></li><li><code>asdf plugin-list-all</code> -&gt; <code>asdf plugin list all</code></li><li><code>asdf plugin-update</code> -&gt; <code>asdf plugin update</code></li><li><code>asdf plugin-remove</code> -&gt; <code>asdf plugin remove</code></li></ul><h3 id="asdf-global-and-asdf-local-commands-have-been-replaced-by-the-asdf-set-command" tabindex="-1"><code>asdf global</code> and <code>asdf local</code> commands have been replaced by the <code>asdf set</code> command <a class="header-anchor" href="#asdf-global-and-asdf-local-commands-have-been-replaced-by-the-asdf-set-command" aria-label="Permalink to &quot;`asdf global` and `asdf local` commands have been replaced by the `asdf set` command&quot;">​</a></h3><p><code>asdf global</code> and <code>asdf local</code> have been replaced by <code>asdf set</code>, which aims to provide the same functionality while using terminology that is less likely to mislead the user. TODO: Add more details here</p><h3 id="asdf-update-command-has-been-removed" tabindex="-1"><code>asdf update</code> command has been removed <a class="header-anchor" href="#asdf-update-command-has-been-removed" aria-label="Permalink to &quot;`asdf update` command has been removed&quot;">​</a></h3><p>Updates can no longer be performed this way. Use your OS package manager or download the latest binary manually. Additionally, the <code>asdf update</code> command present in versions 0.14.1 and older cannot upgrade to version 0.15.0 because the install process has changed. <strong>You cannot upgrade to the latest Go implementation using <code>asdf update</code>.</strong></p><h3 id="asdf-shell-command-has-been-removed" tabindex="-1"><code>asdf shell</code> command has been removed <a class="header-anchor" href="#asdf-shell-command-has-been-removed" aria-label="Permalink to &quot;`asdf shell` command has been removed&quot;">​</a></h3><p>This command actually set an environment variable in the user&#39;s current shell session. It was able to do this because <code>asdf</code> was actually a shell function, not an executable. The new rewrite removes all shell code from asdf, and it is now a binary rather than a shell function, so setting environment variables directly in the shell is no longer possible.</p><h2 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h2><p>Installation of version 0.15.0 is much simpler than previous versions of asdf. It&#39;s just three steps:</p><ul><li>Download the appropriate <code>asdf</code> binary for your operating system/architecture combo and place it in a directory on your <code>$PATH</code></li><li>Set <code>ASDF_DATA_DIR</code> to the directory you&#39;d like asdf to install plugins, versions, and shims.</li><li>Add <code>$ASDF_DATA_DIR/shims</code> to the front of your `$PATH.</li></ul><p>If your operating system&#39;s package manager already offers asdf 0.15.0 that is probably the best method for installing it. Upgrading asdf is now only possible via OS package managers and manual installation. There is no self-upgrade feature.</p><h3 id="upgrading-without-losing-data" tabindex="-1">Upgrading Without Losing Data <a class="header-anchor" href="#upgrading-without-losing-data" aria-label="Permalink to &quot;Upgrading Without Losing Data&quot;">​</a></h3><p>You can upgrade to the latest version of asdf without losing your existing install data. It&#39;s the same sequence of steps as above.</p><h4 id="_1-download-the-appropriate-asdf-binary-for-your-operating-system-architecture" tabindex="-1">1. Download the appropriate <code>asdf</code> binary for your operating system &amp; architecture <a class="header-anchor" href="#_1-download-the-appropriate-asdf-binary-for-your-operating-system-architecture" aria-label="Permalink to &quot;1. Download the appropriate `asdf` binary for your operating system &amp; architecture&quot;">​</a></h4><p>Download the binary and place it in a directory on your path. I chose to place the asdf binary in <code>$HOME/bin</code> and then added <code>$HOME/bin</code> to the front of my <code>$PATH</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki github-dark vp-code-dark"><code><span class="line"><span style="color:#e1e4e8;"># In .zshrc, .bashrc, etc...</span></span>\n<span class="line"><span style="color:#e1e4e8;">export PATH=&quot;$HOME/bin:$PATH&quot;`</span></span></code></pre><pre class="shiki github-light vp-code-light"><code><span class="line"><span style="color:#24292e;"># In .zshrc, .bashrc, etc...</span></span>\n<span class="line"><span style="color:#24292e;">export PATH=&quot;$HOME/bin:$PATH&quot;`</span></span></code></pre></div><h4 id="_2-set-asdf-data-dir" tabindex="-1">2. Set <code>ASDF_DATA_DIR</code> <a class="header-anchor" href="#_2-set-asdf-data-dir" aria-label="Permalink to &quot;2. Set `ASDF_DATA_DIR`&quot;">​</a></h4><p>Run <code>asdf info</code> and copy the line containing the <code>ASDF_DATA_DIR</code> variable:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki github-dark vp-code-dark"><code><span class="line"><span style="color:#e1e4e8;">...</span></span>\n<span class="line"><span style="color:#e1e4e8;">ASDF_DATA_DIR=&quot;/home/myuser/.asdf&quot;</span></span>\n<span class="line"><span style="color:#e1e4e8;">...</span></span></code></pre><pre class="shiki github-light vp-code-light"><code><span class="line"><span style="color:#24292e;">...</span></span>\n<span class="line"><span style="color:#24292e;">ASDF_DATA_DIR=&quot;/home/myuser/.asdf&quot;</span></span>\n<span class="line"><span style="color:#24292e;">...</span></span></code></pre></div><p>In your shell RC file (<code>.zshrc</code> if Zsh, <code>.bashrc</code> if Bash, etc...) add a line to the end setting <code>ASDF_DATA_DIR</code> to that same value:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki github-dark vp-code-dark"><code><span class="line"><span style="color:#F97583;">export</span><span style="color:#E1E4E8;"> ASDF_DATA_DIR</span><span style="color:#F97583;">=</span><span style="color:#9ECBFF;">&quot;/home/myuser/.asdf&quot;</span></span></code></pre><pre class="shiki github-light vp-code-light"><code><span class="line"><span style="color:#D73A49;">export</span><span style="color:#24292E;"> ASDF_DATA_DIR</span><span style="color:#D73A49;">=</span><span style="color:#032F62;">&quot;/home/myuser/.asdf&quot;</span></span></code></pre></div><h4 id="_3-add-asdf-data-dir-shims-to-the-front-of-your-path" tabindex="-1">3. Add <code>$ASDF_DATA_DIR/shims</code> to the front of your `$PATH <a class="header-anchor" href="#_3-add-asdf-data-dir-shims-to-the-front-of-your-path" aria-label="Permalink to &quot;3. Add `$ASDF_DATA_DIR/shims` to the front of your `$PATH&quot;">​</a></h4><p>In your shell RC file (same file as step #2) add <code>$ASDF_DATA_DIR/shims</code> to the front of your path:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki github-dark vp-code-dark"><code><span class="line"><span style="color:#F97583;">export</span><span style="color:#E1E4E8;"> ASDF_DATA_DIR</span><span style="color:#F97583;">=</span><span style="color:#9ECBFF;">&quot;/home/myuser/.asdf&quot;</span></span>\n<span class="line"><span style="color:#F97583;">export</span><span style="color:#E1E4E8;"> PATH</span><span style="color:#F97583;">=</span><span style="color:#9ECBFF;">&quot;</span><span style="color:#E1E4E8;">$ASDF_DATA_DIR</span><span style="color:#9ECBFF;">/shims:</span><span style="color:#E1E4E8;">$PATH</span><span style="color:#9ECBFF;">&quot;</span></span></code></pre><pre class="shiki github-light vp-code-light"><code><span class="line"><span style="color:#D73A49;">export</span><span style="color:#24292E;"> ASDF_DATA_DIR</span><span style="color:#D73A49;">=</span><span style="color:#032F62;">&quot;/home/myuser/.asdf&quot;</span></span>\n<span class="line"><span style="color:#D73A49;">export</span><span style="color:#24292E;"> PATH</span><span style="color:#D73A49;">=</span><span style="color:#032F62;">&quot;</span><span style="color:#24292E;">$ASDF_DATA_DIR</span><span style="color:#032F62;">/shims:</span><span style="color:#24292E;">$PATH</span><span style="color:#032F62;">&quot;</span></span></code></pre></div><h3 id="testing" tabindex="-1">Testing <a class="header-anchor" href="#testing" aria-label="Permalink to &quot;Testing&quot;">​</a></h3><p>If you aren&#39;t sure if the upgrade to 0.15.0 will break things for you can you can test by installing 0.15.0 in addition to your existing version as described above in &quot;Upgrading Without Losing Data&quot;. If it turns out that the upgrade to 0.15.0 breaks things for you simply remove the lines you added to your shell RC file.</p>',31),d=[t];function l(r,i,c,p,h,u){return a(),s("div",null,d)}const g=e(n,[["render",l]]);export{f as __pageData,g as default};
